[DataEventHandler(tableStr(SalesPackingSlipHeaderTmp), DataEventType::Inserting)]
/// <summary>
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
public static void SalesPackingSlipHeaderTmp_onInserting(Common sender, DataEventArgs e)
{
    DirPartyTable                   dirPartyTable;
    DirPartyLocation                dirPartyLocation;
    TaxRegistration                 taxRegistration;
    SalesLine                       salesline;
    ETG_BillOfLading                eTG_BillOfLading;
    SalesTable                      salesTable;
    ETG_SalesTableTrade             eTG_SalesTableTrade;
    InventDim                       InventDim;
    Name                            TeleFax;
    CustPackingSlipJour             custPackingSlipJour;

    SalesPackingSlipHeaderTmp  salesPackingSlipHeaderTmp = sender as SalesPackingSlipHeaderTmp;
    salesline = SalesLine::find(salesPackingSlipHeaderTmp.SalesId);
    select firstonly eTG_SalesTableTrade
        where eTG_SalesTableTrade.SalesId == salesPackingSlipHeaderTmp.SalesId;
           select firstonly RegistrationNumber from  taxRegistration
           exists join dirPartyLocation
           where  dirPartyLocation.RecId == taxRegistration.DirPartyLocation
           exists join dirPartyTable
           where dirPartyTable.RecId    == dirPartyLocation.Party; 
     select firstonly  eTG_BillOfLading
        where eTG_BillOfLading.SalesId  == salesPackingSlipHeaderTmp.SalesId
         && eTG_BillOfLading.PackingSlipId == salesPackingSlipHeaderTmp.PackingSlipId
        && eTG_BillOfLading.DeliveryDate == salesPackingSlipHeaderTmp.DeliveryDate;
        //join salesPackingSlipHeaderTmp
        //where salesPackingSlipHeaderTmp.SalesId == eTG_BillOfLading.SalesId


    salesPackingSlipHeaderTmp.ETGVessel                       = eTG_SalesTableTrade.VesselName;
    salesPackingSlipHeaderTmp.ETGNotify                       = eTG_SalesTableTrade.Name;
    salesPackingSlipHeaderTmp.ETGCosignee                     = eTG_SalesTableTrade.Consignee;
    salesPackingSlipHeaderTmp.ETGPortofdischarge              = eTG_SalesTableTrade.PortOfDischargeDesc;
    salesPackingSlipHeaderTmp.ETGPortofloading                = eTG_SalesTableTrade.PortOfLoadingDesc;
    salesPackingSlipHeaderTmp.ETGCosigneeOnAccountOf          = eTG_SalesTableTrade.OnAccountOf;
    salesPackingSlipHeaderTmp.ETGCosigneeDeliveryDescription  = eTG_SalesTableTrade.DeliveryDescription;
    salesPackingSlipHeaderTmp.ETGNotifyAddress                = eTG_SalesTableTrade.Address;
    salesPackingSlipHeaderTmp.PurchaseOrder                   = salesTable::find(salesPackingSlipHeaderTmp.SalesId).PurchOrderFormNum;
    salesPackingSlipHeaderTmp.CustomerRef                     = salesTable::find(salesPackingSlipHeaderTmp.SalesId).CustomerRef;
    salesPackingSlipHeaderTmp.ETGInventLocationId             = InventDim::find(salesline.InventDimId).InventLocationId;
    salesPackingSlipHeaderTmp.ETGconfigId                     = InventDim::find(salesline.InventDimId).configId;
    salesPackingSlipHeaderTmp.ETGWeb                          = CompanyInfo::find().url();
    salesPackingSlipHeaderTmp.CompanyEmail                    = CompanyInfo::find().email();
    salesPackingSlipHeaderTmp.CompanyRegNum                   = taxRegistration.RegistrationNumber;
    TeleFax                                                   = 'Tel : ' + CompanyInfo::find().phone() + '   Fax :' + CompanyInfo::find().teleFax();
    salesPackingSlipHeaderTmp.ETGCompanyTeleFax               = TeleFax;
    salesPackingSlipHeaderTmp.CompanyAddress                  = CompanyInfo::find().postalAddress().Address;
    salesPackingSlipHeaderTmp.CompanyAddress                  = strReplace(salesPackingSlipHeaderTmp.CompanyAddress,'\n',' ');
    salesPackingSlipHeaderTmp.CompanyName                     = CompanyInfo::find().Name;
    salesPackingSlipHeaderTmp.CompanyEmail                    = strFmt('Email : %1  Web : %2',CompanyInfo::find().email(),CompanyInfo::find().url());
    salesPackingSlipHeaderTmp.ETGExternal                     = salesline.ExternalItemId;
    salesPackingSlipHeaderTmp.DlvTerms                        = SalesTable::find(salesPackingSlipHeaderTmp.SalesId).DlvTerm;
    salesPackingSlipHeaderTmp.ETGBOLNo                        = eTG_BillOfLading.BOLNo;
    salesPackingSlipHeaderTmp.ETGBOLDate                      = eTG_BillOfLading.BOLDate;
    salesPackingSlipHeaderTmp.ETGNumberOfContainers           = eTG_BillOfLading.NumberOfContainers;
    salesPackingSlipHeaderTmp.ETGNumberOfBags                 = eTG_BillOfLading.NumberOfBags;
    salesPackingSlipHeaderTmp.ETGGrossWeight                  = eTG_BillOfLading.GrossWeight;
    salesPackingSlipHeaderTmp.ETGNetWeight                    = eTG_BillOfLading.NetWeight;
    salesPackingSlipHeaderTmp.ETGContainerNumber              = eTG_BillOfLading.ContainerNumber;
    salesPackingSlipHeaderTmp.ETGSealNum                      = eTG_BillOfLading.AgentSealNum;
}
